/**
 * Code Hygiene Validation Tests
 *
 * Validates code quality standards:
 * - Clean Code principles (functions ≤30 lines, files ≤400 lines)
 * - SOLID principles compliance
 * - DRY principle adherence
 * - Cyclomatic complexity (≤15 per function)
 * - Naming conventions
 * - Comment quality
 *
 * @see ISO/IEC 5055 Source Code Quality
 * @see ISO/IEC 25010 Maintainability
 */

import * as fs from 'fs';
import * as path from 'path';

describe('Code Hygiene Validation', () => {
  const srcDir = path.join(__dirname, '../../../../');

  function getAllTsFiles(dir: string, files: string[] = []): string[] {
    const entries = fs.readdirSync(dir, { withFileTypes: true });
    for (const entry of entries) {
      const fullPath = path.join(dir, entry.name);
      if (
        entry.isDirectory() &&
        !entry.name.includes('node_modules') &&
        !entry.name.includes('dist') &&
        !entry.name.includes('coverage')
      ) {
        getAllTsFiles(fullPath, files);
      } else if (
        entry.isFile() &&
        entry.name.endsWith('.ts') &&
        !entry.name.includes('.spec.') &&
        !entry.name.includes('.test.')
      ) {
        files.push(fullPath);
      }
    }
    return files;
  }

  describe('File Size Limits', () => {
    it('should have files under 400 lines', () => {
      const files = getAllTsFiles(srcDir);
      const violations: string[] = [];

      for (const file of files) {
        const content = fs.readFileSync(file, 'utf-8');
        const lineCount = content.split('\n').length;

        if (lineCount > 400) {
          violations.push(`${path.relative(srcDir, file)}: ${lineCount} lines (max 400)`);
        }
      }

      if (violations.length > 0) {
        console.warn('Files exceeding 400 lines:\n' + violations.join('\n'));
      }
      // Allow some violations but flag them
      expect(violations.length).toBeLessThan(50);
    });
  });

  describe('Function Length', () => {
    it('should have functions under 30 lines', () => {
      const files = getAllTsFiles(srcDir);
      const violations: string[] = [];

      for (const file of files) {
        const content = fs.readFileSync(file, 'utf-8');
        const lines = content.split('\n');

        let inFunction = false;
        let functionStart = 0;
        let braceCount = 0;
        let currentFunctionName = '';

        for (let i = 0; i < lines.length; i++) {
          const line = lines[i];

          // Detect function start
          const funcMatch = line.match(
            /(?:async\s+)?(?:function|(?:private|public|protected)?\s*(?:static)?\s*(?:async)?\s*\w+)\s*\([^)]*\)\s*(?::\s*[^{]+)?\s*\{/,
          );
          const arrowMatch = line.match(
            /(?:const|let|var)\s+(\w+)\s*=\s*(?:async\s*)?\([^)]*\)\s*(?::\s*[^=]+)?\s*=>\s*\{/,
          );

          if (funcMatch || arrowMatch) {
            if (!inFunction) {
              inFunction = true;
              functionStart = i;
              currentFunctionName = arrowMatch
                ? arrowMatch[1]
                : line.match(/(\w+)\s*\(/)?.[1] || 'anonymous';
              braceCount = (line.match(/\{/g) || []).length - (line.match(/\}/g) || []).length;
            }
          }

          if (inFunction) {
            braceCount += (line.match(/\{/g) || []).length;
            braceCount -= (line.match(/\}/g) || []).length;

            if (braceCount === 0) {
              const functionLength = i - functionStart + 1;
              if (functionLength > 30) {
                violations.push(
                  `${path.relative(srcDir, file)}:${functionStart + 1} ${currentFunctionName}(): ${functionLength} lines`,
                );
              }
              inFunction = false;
            }
          }
        }
      }

      if (violations.length > 0) {
        console.warn('Functions exceeding 30 lines:\n' + violations.slice(0, 10).join('\n'));
      }
      // Allow some violations but flag them
      expect(violations.length).toBeLessThan(100);
    });
  });

  describe('Naming Conventions', () => {
    it('should use PascalCase for classes', () => {
      const files = getAllTsFiles(srcDir);
      const violations: string[] = [];

      for (const file of files) {
        const content = fs.readFileSync(file, 'utf-8');
        const classMatches = content.match(/class\s+([a-zA-Z_][a-zA-Z0-9_]*)/g);

        if (classMatches) {
          for (const match of classMatches) {
            const className = match.replace('class ', '');
            if (!/^[A-Z][a-zA-Z0-9]*$/.test(className)) {
              violations.push(`Non-PascalCase class: ${className} in ${path.basename(file)}`);
            }
          }
        }
      }

      expect(violations).toEqual([]);
    });

    it('should use camelCase for functions and variables', () => {
      const files = getAllTsFiles(srcDir);
      const violations: string[] = [];

      for (const file of files) {
        const content = fs.readFileSync(file, 'utf-8');

        // Check function names (excluding class methods)
        const funcMatches = content.match(/function\s+([a-zA-Z_][a-zA-Z0-9_]*)/g);
        if (funcMatches) {
          for (const match of funcMatches) {
            const funcName = match.replace('function ', '');
            if (!/^[a-z][a-zA-Z0-9]*$/.test(funcName) && funcName !== '_') {
              violations.push(`Non-camelCase function: ${funcName} in ${path.basename(file)}`);
            }
          }
        }
      }

      // Allow some violations (decorators, etc.)
      expect(violations.length).toBeLessThan(10);
    });

    it('should use UPPER_SNAKE_CASE for constants', () => {
      const files = getAllTsFiles(srcDir);
      let hasProperConstants = true;

      for (const file of files) {
        const content = fs.readFileSync(file, 'utf-8');

        // Check for const with all uppercase names
        const constMatches = content.match(/const\s+([A-Z][A-Z0-9_]*)\s*=/g);
        if (constMatches) {
          for (const match of constMatches) {
            const constName = match.match(/const\s+([A-Z][A-Z0-9_]*)/)?.[1];
            if (constName && !/^[A-Z][A-Z0-9_]*$/.test(constName)) {
              hasProperConstants = false;
            }
          }
        }
      }

      expect(hasProperConstants).toBe(true);
    });
  });

  describe('Code Duplication (DRY)', () => {
    it('should not have excessive code duplication', () => {
      const files = getAllTsFiles(srcDir);
      const codeBlocks: Map<string, string[]> = new Map();

      for (const file of files) {
        const content = fs.readFileSync(file, 'utf-8');
        const lines = content.split('\n');

        // Check for 5+ line blocks that might be duplicated
        for (let i = 0; i < lines.length - 5; i++) {
          const block = lines
            .slice(i, i + 5)
            .join('\n')
            .trim();
          if (block.length > 50) {
            const normalized = block.replace(/\s+/g, ' ');
            const existing = codeBlocks.get(normalized) || [];
            existing.push(`${path.basename(file)}:${i + 1}`);
            codeBlocks.set(normalized, existing);
          }
        }
      }

      const duplicates: string[] = [];
      for (const [, locations] of codeBlocks) {
        if (locations.length > 2) {
          duplicates.push(
            `Block duplicated ${locations.length} times: ${locations.slice(0, 3).join(', ')}`,
          );
        }
      }

      if (duplicates.length > 0) {
        console.warn('Potential code duplication found:\n' + duplicates.slice(0, 5).join('\n'));
      }
      // Some duplication is acceptable in a growing codebase
      expect(duplicates.length).toBeLessThan(500);
    });
  });

  describe('Dead Code Detection', () => {
    it('should not have commented-out code blocks', () => {
      const files = getAllTsFiles(srcDir);
      const violations: string[] = [];

      for (const file of files) {
        const content = fs.readFileSync(file, 'utf-8');
        const lines = content.split('\n');

        let consecutiveCommentedCode = 0;
        for (const line of lines) {
          // Detect commented-out code (not JSDoc or regular comments)
          if (line.match(/^\s*\/\/\s*(const|let|var|function|if|for|while|return|import|export)/)) {
            consecutiveCommentedCode++;
          } else {
            if (consecutiveCommentedCode >= 3) {
              violations.push(`Commented-out code block in ${path.basename(file)}`);
            }
            consecutiveCommentedCode = 0;
          }
        }
      }

      expect(violations.length).toBeLessThan(10);
    });

    it('should not have unused imports', () => {
      // This is usually handled by ESLint, but we can do a basic check
      const files = getAllTsFiles(srcDir);
      const violations: string[] = [];

      for (const file of files) {
        const content = fs.readFileSync(file, 'utf-8');

        // Extract imported names
        const importMatches = content.match(/import\s+\{([^}]+)\}/g);
        if (importMatches) {
          for (const match of importMatches) {
            const imports =
              match
                .match(/\{([^}]+)\}/)?.[1]
                .split(',')
                .map((s) => s.trim().split(' ')[0]) || [];
            for (const imp of imports) {
              if (imp && !imp.includes('type')) {
                const usageCount = (content.match(new RegExp(`\\b${imp}\\b`, 'g')) || []).length;
                // Should appear more than once (the import itself)
                if (usageCount === 1) {
                  violations.push(`Potentially unused import: ${imp} in ${path.basename(file)}`);
                }
              }
            }
          }
        }
      }

      // Allow some - this is a heuristic check
      expect(violations.length).toBeLessThan(20);
    });
  });

  describe('Comment Quality', () => {
    it('should have JSDoc for public methods in services', () => {
      const serviceFiles = getAllTsFiles(srcDir).filter((f) => f.includes('.service.ts'));
      let hasJsDoc = false;

      for (const file of serviceFiles) {
        const content = fs.readFileSync(file, 'utf-8');

        if (content.includes('/**') && content.includes('*/')) {
          hasJsDoc = true;
          break;
        }
      }

      expect(hasJsDoc).toBe(true);
    });

    it('should not have TODO comments older than sprint', () => {
      const files = getAllTsFiles(srcDir);
      const todos: string[] = [];

      for (const file of files) {
        const content = fs.readFileSync(file, 'utf-8');
        const todoMatches = content.match(/\/\/\s*TODO[:\s].*$/gm);

        if (todoMatches) {
          for (const todo of todoMatches) {
            todos.push(`${path.basename(file)}: ${todo.substring(0, 50)}...`);
          }
        }
      }

      if (todos.length > 10) {
        console.warn(`Found ${todos.length} TODO comments - consider addressing them`);
      }
      // TODOs are allowed but flagged
      expect(todos.length).toBeLessThan(50);
    });
  });

  describe('Async/Await Usage', () => {
    it('should use async/await instead of .then()', () => {
      const files = getAllTsFiles(srcDir);
      const violations: string[] = [];

      for (const file of files) {
        const content = fs.readFileSync(file, 'utf-8');

        // Count .then() usage vs async/await
        const thenCount = (content.match(/\.then\s*\(/g) || []).length;
        const asyncCount = (content.match(/async\s+/g) || []).length;

        // If file uses promises, should prefer async/await
        if (thenCount > 5 && thenCount > asyncCount) {
          violations.push(
            `${path.basename(file)}: ${thenCount} .then() calls (prefer async/await)`,
          );
        }
      }

      expect(violations.length).toBeLessThan(5);
    });
  });

  describe('Error Handling', () => {
    it('should have try-catch blocks for async operations', () => {
      const files = getAllTsFiles(srcDir);
      let hasTryCatch = false;

      for (const file of files) {
        const content = fs.readFileSync(file, 'utf-8');

        if (content.includes('try {') && content.includes('catch')) {
          hasTryCatch = true;
          break;
        }
      }

      expect(hasTryCatch).toBe(true);
    });

    it('should not have empty catch blocks', () => {
      const files = getAllTsFiles(srcDir);
      const violations: string[] = [];

      for (const file of files) {
        const content = fs.readFileSync(file, 'utf-8');

        // Find empty catch blocks
        const emptyCatch = content.match(/catch\s*\([^)]*\)\s*\{\s*\}/g);
        if (emptyCatch) {
          violations.push(`Empty catch block in ${path.basename(file)}`);
        }
      }

      expect(violations).toEqual([]);
    });
  });

  describe('Type Safety', () => {
    it('should minimize use of "any" type', () => {
      const files = getAllTsFiles(srcDir);
      let anyCount = 0;

      for (const file of files) {
        const content = fs.readFileSync(file, 'utf-8');
        const matches = content.match(/:\s*any\b/g);
        if (matches) {
          anyCount += matches.length;
        }
      }

      if (anyCount > 50) {
        console.warn(`Found ${anyCount} uses of 'any' type - consider using specific types`);
      }
      expect(anyCount).toBeLessThan(150);
    });

    it('should use strict null checks patterns', () => {
      const files = getAllTsFiles(srcDir);
      let hasNullChecks = false;

      for (const file of files) {
        const content = fs.readFileSync(file, 'utf-8');

        if (
          content.includes('??') ||
          content.includes('?.') ||
          content.includes('!== null') ||
          content.includes('!== undefined')
        ) {
          hasNullChecks = true;
          break;
        }
      }

      expect(hasNullChecks).toBe(true);
    });
  });

  describe('Module Organization', () => {
    it('should have index.ts barrel files for modules', () => {
      const modulesDir = path.join(srcDir, 'modules');
      if (!fs.existsSync(modulesDir)) {
        // Skip if modules directory doesn't exist at expected path
        expect(true).toBe(true);
        return;
      }

      const moduleDirs = fs
        .readdirSync(modulesDir, { withFileTypes: true })
        .filter((d) => d.isDirectory());

      let hasBarrelFiles = 0;
      for (const dir of moduleDirs) {
        const indexPath = path.join(modulesDir, dir.name, 'index.ts');
        if (fs.existsSync(indexPath)) {
          hasBarrelFiles++;
        }
      }

      // At least half should have index files
      expect(hasBarrelFiles).toBeGreaterThan(moduleDirs.length / 2);
    });
  });
});

/**
 * Chaos Engineering Configuration
 *
 * Defines chaos experiments for resilience testing using Azure Chaos Studio
 * and Chaos Mesh for Kubernetes environments.
 *
 * Purpose:
 * - Test system resilience under failure conditions
 * - Validate graceful degradation mechanisms
 * - Verify recovery procedures
 * - Ensure SLA targets during failures
 */

// =============================================================================
// CHAOS CONFIGURATION TYPES
// =============================================================================

export interface ChaosExperimentConfig {
  id: string;
  name: string;
  description: string;
  type: ChaosExperimentType;
  target: ChaosTarget;
  parameters: ChaosParameters;
  schedule: ChaosSchedule;
  rollback: RollbackConfig;
  monitoring: MonitoringConfig;
  enabled: boolean;
}

export type ChaosExperimentType =
  | 'network-latency'
  | 'network-partition'
  | 'cpu-pressure'
  | 'memory-pressure'
  | 'disk-pressure'
  | 'pod-kill'
  | 'pod-failure'
  | 'container-kill'
  | 'dns-chaos'
  | 'http-chaos'
  | 'io-chaos'
  | 'time-chaos'
  | 'jvm-chaos'
  | 'kernel-chaos'
  | 'stress-ng';

export interface ChaosTarget {
  resourceType:
    | 'container-app'
    | 'kubernetes-pod'
    | 'virtual-machine'
    | 'database'
    | 'storage'
    | 'network';
  resourceGroup?: string;
  namespace?: string;
  selector?: Record<string, string>;
  names?: string[];
  percentage?: number;
}

export interface ChaosParameters {
  duration: string;
  intensity?: number;
  latencyMs?: number;
  jitterMs?: number;
  packetLossPercent?: number;
  bandwidthLimit?: string;
  cpuPercent?: number;
  memoryBytes?: string;
  diskFillPercent?: number;
  errorRate?: number;
  httpStatusCode?: number;
  targetPort?: number;
}

export interface ChaosSchedule {
  type: 'manual' | 'scheduled' | 'continuous';
  cron?: string;
  timezone?: string;
  maxOccurrences?: number;
  gameDay?: boolean;
}

export interface RollbackConfig {
  automatic: boolean;
  triggerConditions: RollbackTrigger[];
  timeoutSeconds: number;
}

export interface RollbackTrigger {
  metric: string;
  operator: 'gt' | 'lt' | 'eq' | 'gte' | 'lte';
  threshold: number;
  evaluationWindow: string;
}

export interface MonitoringConfig {
  alertsEnabled: boolean;
  dashboardUrl?: string;
  metricsToWatch: string[];
  notificationChannels: string[];
}

// =============================================================================
// AZURE CHAOS STUDIO CONFIGURATION
// =============================================================================

export interface AzureChaosStudioConfig {
  subscriptionId: string;
  resourceGroup: string;
  location: string;
  managedIdentityId: string;
  targetResourceIds: string[];
  experiments: AzureChaosExperiment[];
}

export interface AzureChaosExperiment {
  name: string;
  identity: {
    type: 'SystemAssigned' | 'UserAssigned';
    userAssignedIdentities?: Record<string, object>;
  };
  properties: {
    selectors: AzureChaosSelector[];
    steps: AzureChaosStep[];
  };
}

export interface AzureChaosSelector {
  type: 'List' | 'Query';
  id: string;
  targets: AzureChaosTargetReference[];
}

export interface AzureChaosTargetReference {
  type: string;
  id: string;
}

export interface AzureChaosStep {
  name: string;
  branches: AzureChaosBranch[];
}

export interface AzureChaosBranch {
  name: string;
  actions: AzureChaosAction[];
}

export interface AzureChaosAction {
  type: 'continuous' | 'discrete' | 'delay';
  name: string;
  selectorId?: string;
  duration?: string;
  parameters?: AzureChaosActionParameter[];
}

export interface AzureChaosActionParameter {
  key: string;
  value: string;
}

// =============================================================================
// CHAOS MESH CONFIGURATION (Kubernetes)
// =============================================================================

export interface ChaosMeshConfig {
  version: string;
  namespace: string;
  dashboard: {
    enabled: boolean;
    port: number;
    ingress?: {
      enabled: boolean;
      host: string;
    };
  };
  experiments: ChaosMeshExperiment[];
}

export interface ChaosMeshExperiment {
  apiVersion: string;
  kind: ChaosMeshKind;
  metadata: {
    name: string;
    namespace: string;
    labels?: Record<string, string>;
    annotations?: Record<string, string>;
  };
  spec: ChaosMeshSpec;
}

export type ChaosMeshKind =
  | 'PodChaos'
  | 'NetworkChaos'
  | 'IOChaos'
  | 'TimeChaos'
  | 'StressChaos'
  | 'DNSChaos'
  | 'HTTPChaos'
  | 'KernelChaos'
  | 'JVMChaos'
  | 'AWSChaos'
  | 'AzureChaos'
  | 'GCPChaos';

export interface ChaosMeshSpec {
  mode: 'one' | 'all' | 'fixed' | 'fixed-percent' | 'random-max-percent';
  value?: string;
  selector: ChaosMeshSelector;
  duration?: string;
  scheduler?: ChaosMeshScheduler;
  // Specific chaos parameters
  action?: string;
  delay?: ChaosMeshDelay;
  loss?: ChaosMeshLoss;
  duplicate?: ChaosMeshDuplicate;
  corrupt?: ChaosMeshCorrupt;
  bandwidth?: ChaosMeshBandwidth;
  stressors?: ChaosMeshStressors;
}

export interface ChaosMeshSelector {
  namespaces?: string[];
  labelSelectors?: Record<string, string>;
  expressionSelectors?: ChaosMeshExpressionSelector[];
  fieldSelectors?: Record<string, string>;
  pods?: Record<string, string[]>;
}

export interface ChaosMeshExpressionSelector {
  key: string;
  operator: 'In' | 'NotIn' | 'Exists' | 'DoesNotExist';
  values?: string[];
}

export interface ChaosMeshScheduler {
  cron: string;
  duration?: string;
}

export interface ChaosMeshDelay {
  latency: string;
  correlation?: string;
  jitter?: string;
}

export interface ChaosMeshLoss {
  loss: string;
  correlation?: string;
}

export interface ChaosMeshDuplicate {
  duplicate: string;
  correlation?: string;
}

export interface ChaosMeshCorrupt {
  corrupt: string;
  correlation?: string;
}

export interface ChaosMeshBandwidth {
  rate: string;
  limit: number;
  buffer: number;
}

export interface ChaosMeshStressors {
  memory?: {
    workers: number;
    size?: string;
  };
  cpu?: {
    workers: number;
    load?: number;
  };
}

// =============================================================================
// DEFAULT CHAOS EXPERIMENTS
// =============================================================================

export function getDefaultChaosExperiments(): ChaosExperimentConfig[] {
  return [
    // Database Connection Failure
    {
      id: 'exp-db-timeout',
      name: 'Database Connection Timeout',
      description:
        'Simulate database connection timeout to test circuit breaker and fallback mechanisms',
      type: 'network-latency',
      target: {
        resourceType: 'database',
        names: ['quiz2biz-db'],
      },
      parameters: {
        duration: '5m',
        latencyMs: 30000, // 30 second delay = timeout
      },
      schedule: {
        type: 'manual',
        gameDay: true,
      },
      rollback: {
        automatic: true,
        triggerConditions: [
          { metric: 'error_rate', operator: 'gt', threshold: 5, evaluationWindow: '1m' },
          { metric: 'p99_latency_ms', operator: 'gt', threshold: 10000, evaluationWindow: '1m' },
        ],
        timeoutSeconds: 300,
      },
      monitoring: {
        alertsEnabled: true,
        metricsToWatch: ['db_connection_errors', 'circuit_breaker_state', 'fallback_invocations'],
        notificationChannels: ['slack-chaos-alerts', 'pagerduty'],
      },
      enabled: true,
    },

    // External API Timeout
    {
      id: 'exp-api-timeout',
      name: 'External API Timeout',
      description: 'Simulate external API timeout (Stripe, SendGrid) to test retry and fallback',
      type: 'http-chaos',
      target: {
        resourceType: 'network',
        selector: { 'external-service': 'true' },
      },
      parameters: {
        duration: '3m',
        latencyMs: 35000, // 35 second delay
        errorRate: 0.5, // 50% of requests affected
      },
      schedule: {
        type: 'scheduled',
        cron: '0 3 * * 0', // Sunday 3 AM
        timezone: 'UTC',
      },
      rollback: {
        automatic: true,
        triggerConditions: [
          { metric: 'external_api_errors', operator: 'gt', threshold: 20, evaluationWindow: '1m' },
        ],
        timeoutSeconds: 180,
      },
      monitoring: {
        alertsEnabled: true,
        metricsToWatch: ['external_api_latency', 'retry_count', 'queue_depth'],
        notificationChannels: ['slack-chaos-alerts'],
      },
      enabled: true,
    },

    // Network Latency - Moderate
    {
      id: 'exp-network-latency-500ms',
      name: 'Network Latency 500ms',
      description: 'Inject 500ms network latency to test performance degradation handling',
      type: 'network-latency',
      target: {
        resourceType: 'container-app',
        selector: { app: 'quiz2biz-api' },
        percentage: 50,
      },
      parameters: {
        duration: '10m',
        latencyMs: 500,
        jitterMs: 100,
      },
      schedule: {
        type: 'manual',
        gameDay: true,
      },
      rollback: {
        automatic: true,
        triggerConditions: [
          { metric: 'p95_latency_ms', operator: 'gt', threshold: 2000, evaluationWindow: '2m' },
        ],
        timeoutSeconds: 600,
      },
      monitoring: {
        alertsEnabled: true,
        metricsToWatch: ['request_latency', 'timeout_rate', 'user_experience_score'],
        notificationChannels: ['slack-chaos-alerts'],
      },
      enabled: true,
    },

    // Network Latency - Severe
    {
      id: 'exp-network-latency-2000ms',
      name: 'Network Latency 2000ms',
      description: 'Inject 2000ms network latency to test extreme degradation and timeouts',
      type: 'network-latency',
      target: {
        resourceType: 'container-app',
        selector: { app: 'quiz2biz-api' },
        percentage: 25,
      },
      parameters: {
        duration: '5m',
        latencyMs: 2000,
        jitterMs: 500,
      },
      schedule: {
        type: 'manual',
        gameDay: true,
      },
      rollback: {
        automatic: true,
        triggerConditions: [
          { metric: 'p99_latency_ms', operator: 'gt', threshold: 5000, evaluationWindow: '1m' },
          { metric: 'error_rate', operator: 'gt', threshold: 10, evaluationWindow: '1m' },
        ],
        timeoutSeconds: 300,
      },
      monitoring: {
        alertsEnabled: true,
        metricsToWatch: ['request_latency', 'timeout_rate', 'circuit_breaker_trips'],
        notificationChannels: ['slack-chaos-alerts', 'pagerduty'],
      },
      enabled: true,
    },

    // Pod Kill
    {
      id: 'exp-pod-kill',
      name: 'Pod Kill - API Service',
