export interface FeatureFlagConfig {
  key: string;
  name: string;
  description: string;
  kind: FlagKind;
  defaultValue: unknown;
  variations: FlagVariation[];
  targeting: TargetingConfig;
  prerequisites?: PrerequisiteFlag[];
  tags: string[];
  environments: EnvironmentConfig[];
  maintainer?: string;
  createdAt?: Date;
  updatedAt?: Date;
}

export type FlagKind = 'boolean' | 'string' | 'number' | 'json';

export interface FlagVariation {
  value: unknown;
  name: string;
  description?: string;
}

export interface TargetingConfig {
  enabled: boolean;
  rules: TargetingRule[];
  fallthrough: FallthroughConfig;
  offVariation: number;
}

export interface TargetingRule {
  id: string;
  clauses: TargetingClause[];
  variation: number;
  rollout?: RolloutConfig;
  trackEvents?: boolean;
}

export interface TargetingClause {
  attribute: string;
  op: ClauseOperator;
  values: unknown[];
  negate?: boolean;
}

export type ClauseOperator =
  | 'in'
  | 'endsWith'
  | 'startsWith'
  | 'matches'
  | 'contains'
  | 'lessThan'
  | 'lessThanOrEqual'
  | 'greaterThan'
  | 'greaterThanOrEqual'
  | 'before'
  | 'after'
  | 'semVerEqual'
  | 'semVerLessThan'
  | 'semVerGreaterThan';

export interface RolloutConfig {
  variations: WeightedVariation[];
  bucketBy?: string;
}

export interface WeightedVariation {
  variation: number;
  weight: number; // 0-100000 (100% = 100000)
}

export interface FallthroughConfig {
  variation?: number;
  rollout?: RolloutConfig;
}

export interface PrerequisiteFlag {
  key: string;
  variation: number;
}

export interface EnvironmentConfig {
  key: string;
  on: boolean;
  archived: boolean;
  trackEvents: boolean;
  trackEventsFallthrough: boolean;
}

// ============================================================================
// A/B Testing Types
// ============================================================================

export interface ABTestConfig {
  key: string;
  name: string;
  hypothesis: string;
  primaryMetric: string;
  secondaryMetrics: string[];
  variants: ABVariant[];
  allocation: ABAllocation;
  duration: ABTestDuration;
  status: ABTestStatus;
  results?: ABTestResults;
}

export interface ABVariant {
  key: string;
  name: string;
  description: string;
  isControl: boolean;
  allocation: number; // Percentage 0-100
}

export interface ABAllocation {
  type: 'random' | 'percentage' | 'sticky';
  stickyBucket?: string;
  exposurePercentage: number;
}

export interface ABTestDuration {
  startDate: Date;
  endDate?: Date;
  minRuntime: number; // Days
  maxRuntime: number; // Days
  sampleSize: number;
}

export type ABTestStatus = 'draft' | 'running' | 'paused' | 'completed' | 'cancelled';

export interface ABTestResults {
  winner?: string;
  confidence: number;
  metrics: ABMetricResult[];
  recommendation: string;
}

export interface ABMetricResult {
  name: string;
  control: MetricValue;
  treatment: MetricValue;
  uplift: number;
  pValue: number;
  significant: boolean;
}

export interface MetricValue {
  mean: number;
  standardDeviation: number;
  sampleSize: number;
}

// ============================================================================
// LaunchDarkly Configuration
// ============================================================================

export interface LaunchDarklyConfig {
  sdkKey: string;
  clientSideId?: string;
  projectKey: string;
  environmentKey: string;
  baseUri: string;
  eventsUri: string;
  streamUri: string;
  options: LaunchDarklyOptions;
}

export interface LaunchDarklyOptions {
  offline: boolean;
  sendEvents: boolean;
  allAttributesPrivate: boolean;
  privateAttributes: string[];
  flushInterval: number;
  timeout: number;
  capacity: number;
  stream: boolean;
  useLdd: boolean;
  diagnosticOptOut: boolean;
}

/**
 * Get LaunchDarkly configuration
 */
export function getLaunchDarklyConfig(): LaunchDarklyConfig {
  return {
    sdkKey: process.env.LAUNCHDARKLY_SDK_KEY || '',
    clientSideId: process.env.LAUNCHDARKLY_CLIENT_SIDE_ID,
    projectKey: process.env.LAUNCHDARKLY_PROJECT_KEY || 'quiz2biz',
    environmentKey: process.env.NODE_ENV || 'development',
    baseUri: 'https://sdk.launchdarkly.com',
    eventsUri: 'https://events.launchdarkly.com',
    streamUri: 'https://stream.launchdarkly.com',
    options: {
      offline: process.env.LAUNCHDARKLY_OFFLINE === 'true',
      sendEvents: true,
      allAttributesPrivate: false,
      privateAttributes: ['email', 'password', 'creditCard'],
      flushInterval: 5000,
      timeout: 5000,
      capacity: 10000,
      stream: true,
      useLdd: false,
      diagnosticOptOut: false,
    },
  };
}

