export class RetryExecutor {
  async executeWithRetry<T>(
    operation: () => Promise<T>,
    config: RetryConfig,
    context?: string,
  ): Promise<RetryResult<T>> {
    let lastError: Error | undefined;
    let totalDelayMs = 0;

    for (let attempt = 1; attempt <= config.maxRetries + 1; attempt++) {
      try {
        const data = await operation();
        return {
          success: true,
          data,
          attempts: attempt,
          totalDelayMs,
          lastAttemptTime: new Date(),
        };
      } catch (error) {
        lastError = error as Error;
        const errorCode = this.extractErrorCode(error);

        // Check if error is non-retryable
        if (config.nonRetryableErrors.includes(errorCode)) {
          logger.warn(`[Retry] ${context}: Non-retryable error ${errorCode}, aborting`);
          break;
        }

        // Check if error is retryable
        if (!config.retryableErrors.includes(errorCode)) {
          logger.warn(`[Retry] ${context}: Unknown error ${errorCode}, aborting`);
          break;
        }

        if (attempt <= config.maxRetries) {
          const delay = this.calculateDelay(attempt, config);
          totalDelayMs += delay;
          logger.log(
            `[Retry] ${context}: Attempt ${attempt} failed with ${errorCode}, ` +
              `retrying in ${delay}ms (${config.maxRetries - attempt} retries left)`,
          );
          await this.sleep(delay);
        }
      }
    }

    return {
      success: false,
      error: lastError,
      attempts: config.maxRetries + 1,
      totalDelayMs,
      lastAttemptTime: new Date(),
    };
  }

  private calculateDelay(attempt: number, config: RetryConfig): number {
    // Exponential backoff
    const exponentialDelay =
      config.initialDelayMs * Math.pow(config.backoffMultiplier, attempt - 1);

    // Apply max cap
    const cappedDelay = Math.min(exponentialDelay, config.maxDelayMs);

    // Add jitter
    const jitter = cappedDelay * config.jitterFactor * Math.random();

    return Math.floor(cappedDelay + jitter);
  }

  private extractErrorCode(error: unknown): string {
    if (error instanceof Error) {
      // HTTP status code
      if ('status' in error) {
        return String((error as { status: number }).status);
      }
      // Prisma error code
      if ('code' in error) {
        return String((error as { code: string }).code);
      }
      // Node.js error code
      if ('code' in error) {
        return String((error as { code: string }).code);
      }
    }
    return 'UNKNOWN';
  }

  private sleep(ms: number): Promise<void> {
    return new Promise((resolve) => setTimeout(resolve, ms));
  }
}

