  ResourcePressureTestRunner,
};

// Initialize Application Insights FIRST (before any other imports)
// This ensures proper instrumentation of all dependencies
import {
  initializeAppInsights,
  shutdown as shutdownAppInsights,
  createRequestTrackingMiddleware,
} from './config/appinsights.config';
initializeAppInsights();

import { NestFactory } from '@nestjs/core';
import { ValidationPipe, Logger } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { SwaggerModule, DocumentBuilder } from '@nestjs/swagger';
import { Logger as PinoLogger } from 'nestjs-pino';
import helmet from 'helmet';
import compression from 'compression';
import cookieParser from 'cookie-parser';
import { Request, Response, NextFunction, json, urlencoded } from 'express';
import { AppModule } from './app.module';
import { HttpExceptionFilter } from './common/filters/http-exception.filter';
import { TransformInterceptor } from './common/interceptors/transform.interceptor';
import { LoggingInterceptor } from './common/interceptors/logging.interceptor';
import { initializeSentry, captureException } from './config/sentry.config';

// Initialize Sentry after Application Insights
initializeSentry();

async function bootstrap(): Promise<void> {
  const logger = new Logger('Bootstrap');
  const app = await NestFactory.create(AppModule, {
    rawBody: true, // Required for Stripe webhook signature verification
    bufferLogs: true, // Buffer logs until Pino logger is ready
  });

  // Use Pino as the NestJS logger (structured JSON in production)
  app.useLogger(app.get(PinoLogger));

  const configService = app.get(ConfigService);
  const port = configService.get<number>('PORT', 3000);
  const apiPrefix = configService.get<string>('API_PREFIX', 'api/v1');
  const nodeEnv = configService.get<string>('NODE_ENV', 'development');

  // HTTP compression middleware (GAP-P2) — gzip/brotli for response bodies
  // NOTE: Do not compress Server-Sent Events (SSE) or streaming AI gateway responses
  app.use(
    compression({
      filter: (req, res) => {
        const acceptHeader = req.headers.accept ?? '';

        // Skip compression for SSE and streaming endpoints (prefix-aware)
        const url =
          typeof (req as unknown as { originalUrl?: string }).originalUrl === 'string'
            ? (req as unknown as { originalUrl: string }).originalUrl
            : req.url;
        if (typeof url === 'string' && url.includes('/ai-gateway/stream')) {
          return false;
        }

        if (acceptHeader.includes('text/event-stream')) {
          return false;
        }

        // Fallback to default compression filter behavior
        return compression.filter(req, res);
      },
    }),
  );
  // Security middleware with CSP configuration for React SPA
  app.use(
    helmet({
      contentSecurityPolicy: {
        directives: {
          defaultSrc: ["'self'"],
          scriptSrc: [
            "'self'",
            // Allow scripts from same origin and inline scripts for React
            nodeEnv === 'development' ? "'unsafe-inline'" : "'self'",
            // Google Analytics, Stripe, etc.
            'https://www.googletagmanager.com',
            'https://www.google-analytics.com',
            'https://js.stripe.com',
          ].filter(Boolean),
          styleSrc: [
            "'self'",
            "'unsafe-inline'", // Required for React styled-components/emotion
            'https://fonts.googleapis.com',
          ],
          imgSrc: [
            "'self'",
            'data:',
            'blob:',
            'https://www.googletagmanager.com',
            'https://www.google-analytics.com',
            'https://*.stripe.com',
          ],
          fontSrc: ["'self'", 'https://fonts.gstatic.com', 'data:'],
          connectSrc: [
            "'self'",
            'https://www.google-analytics.com',
            'https://api.stripe.com',
            'https://dc.services.visualstudio.com', // Application Insights
            'wss:', // WebSocket for real-time features
          ],
          frameSrc: ["'self'", 'https://js.stripe.com', 'https://hooks.stripe.com'],
          objectSrc: ["'none'"],
          baseUri: ["'self'"],
          formAction: ["'self'"],
          frameAncestors: ["'self'"],
          reportUri: [`/${apiPrefix.replace(/^\/+/, '')}/csp-report`],
          upgradeInsecureRequests: nodeEnv === 'production' ? [] : null,
        },
      },
      // HSTS for production
      strictTransportSecurity:
        nodeEnv === 'production'
          ? {
            maxAge: 31536000, // 1 year
            includeSubDomains: true,
            preload: true,
          }
          : false,
    }),
  );

  // Permissions-Policy header (formerly Feature-Policy)
  // Restricts which browser features the site can use
  app.use((_req: Request, res: Response, next: NextFunction) => {
    res.setHeader(
      'Permissions-Policy',
      [
        // Disable potentially dangerous features
        'accelerometer=()',
        'ambient-light-sensor=()',
        'autoplay=()',
        'battery=()',
        'browsing-topics=()',
        'camera=()',
        'display-capture=()',
        'document-domain=()',
        'encrypted-media=()',
        'execution-while-not-rendered=()',
        'execution-while-out-of-viewport=()',
        'gamepad=()',
        'geolocation=()',
        'gyroscope=()',
        'hid=()',
        'identity-credentials-get=()',
        'idle-detection=()',
        'local-fonts=()',
        'magnetometer=()',
        'microphone=()',
        'midi=()',
        'otp-credentials=()',
        'payment=(self)', // Allow Stripe payment
        'picture-in-picture=()',
        'publickey-credentials-create=()',
        'publickey-credentials-get=()',
        'screen-wake-lock=()',
        'serial=()',
        'speaker-selection=()',
        'storage-access=()',
        'usb=()',
        'web-share=()',
        'xr-spatial-tracking=()',
      ].join(', '),
    );
    next();
  });

  // Application Insights request tracking
  app.use(createRequestTrackingMiddleware());

  // Cookie parser for CSRF tokens
  app.use(cookieParser());

  // Request body size limits (GAP-S2) — prevent oversized payload attacks
  app.use(json({ limit: '1mb' }));
  app.use(urlencoded({ limit: '1mb', extended: true }));

  // CORS configuration - parse comma-separated origins and handle credentials properly
  const corsOrigin = configService.get<string>('CORS_ORIGIN', '*');
  const parsedOrigins = corsOrigin === '*' ? '*' : corsOrigin.split(',').map((o) => o.trim());
  const useCredentials = parsedOrigins !== '*';
  if (!useCredentials && nodeEnv !== 'development') {
    logger.warn('CORS wildcard origin detected in non-dev environment — credentials disabled');
  }
  app.enableCors({
    origin: parsedOrigins,
    methods: 'GET,HEAD,PUT,PATCH,POST,DELETE,OPTIONS',
    credentials: useCredentials,
  });

  // Global prefix
  app.setGlobalPrefix(apiPrefix);

  // Global pipes
  app.useGlobalPipes(
    new ValidationPipe({
      whitelist: true,
      forbidNonWhitelisted: true,
      transform: true,
      transformOptions: {
        enableImplicitConversion: true,
      },
    }),
  );

  // Global filters
  app.useGlobalFilters(new HttpExceptionFilter());

  // Global interceptors
  app.useGlobalInterceptors(new TransformInterceptor(), new LoggingInterceptor());

  // Swagger/OpenAPI documentation — gated by ENABLE_SWAGGER (disabled in production by default)
  const enableSwagger = configService.get<string>(
    'ENABLE_SWAGGER',
    nodeEnv !== 'production' ? 'true' : 'false',
  );
  if (enableSwagger === 'true') {
    const swaggerConfig = new DocumentBuilder()
      .setTitle('Quiz2Biz API')
      .setDescription(
        `## Adaptive Questionnaire System API

This API powers the Quiz2Biz platform - an intelligent assessment tool for organizational readiness.

### Features
- **Authentication**: JWT-based auth with OAuth2 support (Google, Microsoft)
- **Questionnaires**: Adaptive questionnaire flow with 11 question types
- **Scoring**: Real-time readiness scoring across 11 dimensions
- **Documents**: Automated document generation (Technology Roadmap, Business Plan, etc.)
- **Evidence**: Evidence collection and integrity verification

### Rate Limits
- 100 requests per minute per IP
- 1000 requests per hour per authenticated user

### Support
For API issues, contact: support@quiz2biz.com`,
      )
      .setVersion('1.0.0')
      .setContact('Quiz2Biz Team', 'https://quiz2biz.com', 'support@quiz2biz.com')
      .setLicense('Proprietary', 'https://quiz2biz.com/terms')
      .addServer(
        nodeEnv === 'production' ? 'https://api.quiz2biz.com' : `http://localhost:${port}`,
        nodeEnv === 'production' ? 'Production' : 'Development',
      )
      .addBearerAuth(
        {
          type: 'http',
          scheme: 'bearer',
          bearerFormat: 'JWT',
          name: 'Authorization',
          description: 'Enter your JWT access token',
          in: 'header',
        },
        'JWT-auth',
      )
      .addTag('auth', 'Authentication & authorization endpoints')
      .addTag('users', 'User profile management')
      .addTag('questionnaires', 'Questionnaire templates and management')
      .addTag('sessions', 'Assessment sessions and progress')
      .addTag('responses', 'Question responses and validation')
      .addTag('scoring', 'Readiness scoring and heatmaps')
      .addTag('evidence', 'Evidence collection and verification')
      .addTag('documents', 'Document generation and export')
      .addTag('admin', 'Administrative operations')
      .addTag('payment', 'Subscription and billing')
      .addTag('health', 'Health check endpoints')
      .build();

    const openApiDocument = SwaggerModule.createDocument(app, swaggerConfig, {
      operationIdFactory: (_controllerKey: string, methodKey: string) => methodKey,
    });

    // Set up Swagger UI at /api/v1/docs
    SwaggerModule.setup(`${apiPrefix}/docs`, app, openApiDocument, {
      swaggerOptions: {
        persistAuthorization: true,
        docExpansion: 'none',
        filter: true,
        showRequestDuration: true,
        syntaxHighlight: {
          activate: true,
          theme: 'monokai',
        },
      },
      customSiteTitle: 'Quiz2Biz API Documentation',
      customCss: `
      .swagger-ui .topbar { display: none; }
      .swagger-ui .info .title { font-size: 2rem; }
    `,
    });

    logger.log(`Swagger documentation available at /${apiPrefix}/docs`);
  } else {
    logger.log('Swagger documentation is disabled (set ENABLE_SWAGGER=true to enable)');
  }

  // Graceful shutdown
  app.enableShutdownHooks();

  // Handle graceful shutdown for Application Insights
  process.on('SIGTERM', async () => {
    logger.log('SIGTERM received, flushing telemetry...');
    await shutdownAppInsights();
  });

  process.on('SIGINT', async () => {
    logger.log('SIGINT received, flushing telemetry...');
    await shutdownAppInsights();
  });

  await app.listen(port);
  logger.log(`Application is running on: http://localhost:${port}/${apiPrefix}`);
  logger.log(`Environment: ${nodeEnv}`);
}

bootstrap().catch((error: unknown) => {
  const logger = new Logger('Bootstrap');
  logger.error('Failed to start application', error);
  logger.error('Full stack trace:', error instanceof Error ? error.stack : String(error));

  // Capture bootstrap errors in Sentry
  captureException(error instanceof Error ? error : new Error(String(error)), { context: 'bootstrap' });

  process.exit(1);
});

import {
  Controller,
  Get,
  Post,
  Put,
  Delete,
  Body,
  Param,
  Query,
  Headers,
  HttpCode,
  HttpStatus,
  BadRequestException,
  NotFoundException,
  UseGuards,
  Logger,
} from '@nestjs/common';
import {
  ApiTags,
  ApiOperation,
  ApiResponse,
  ApiBearerAuth,
  ApiParam,
  ApiQuery,
} from '@nestjs/swagger';
import * as crypto from 'crypto';
import { IsString, IsBoolean, IsEnum, IsObject, IsOptional, IsUUID } from 'class-validator';
import { JwtAuthGuard } from '../auth/guards/jwt-auth.guard';
import { Public } from '../auth/decorators/public.decorator';
import { GitHubAdapter } from './github.adapter';
import { GitLabAdapter } from './gitlab.adapter';
import { JiraConfluenceAdapter } from './jira-confluence.adapter';
import {
  AdapterConfigService,
  AdapterType,
  AdapterConfig,
  GitHubAdapterConfig,
  GitLabAdapterConfig,
  JiraAdapterConfig,
  ConfluenceAdapterConfig,
} from './adapter-config.service';

// DTOs with class-validator decorators for input validation (GAP-001 fix)
class CreateAdapterConfigDto {
  @IsEnum(['github', 'gitlab', 'jira', 'confluence', 'azure_devops'])
  type!: AdapterType;

  @IsString()
  name!: string;

  @IsBoolean()
  enabled!: boolean;

  @IsObject()
  config!: Record<string, unknown>;
}

class UpdateAdapterConfigDto {
  @IsOptional()
  @IsString()
  name?: string;

  @IsOptional()
  @IsBoolean()
  enabled?: boolean;

  @IsOptional()
  @IsObject()
  config?: Record<string, unknown>;
}

class SyncAdapterDto {
  @IsUUID()
  sessionId!: string;

  @IsOptional()
  @IsObject()
  options?: Record<string, unknown>;
}

class TestAdapterConnectionDto {
  @IsEnum(['github', 'gitlab', 'jira', 'confluence', 'azure_devops'])
  type!: AdapterType;

  @IsObject()
  config!: Record<string, unknown>;
}

@ApiTags('Adapters')
@ApiBearerAuth()
@UseGuards(JwtAuthGuard)
@Controller('adapters')
export class AdapterController {
  constructor(
    private readonly githubAdapter: GitHubAdapter,
    private readonly gitlabAdapter: GitLabAdapter,
    private readonly jiraConfluenceAdapter: JiraConfluenceAdapter,
    private readonly adapterConfigService: AdapterConfigService,
  ) {}

  // ==================== ADAPTER TYPES ====================

  @Get('types')
  @ApiOperation({ summary: 'Get all supported adapter types' })
  @ApiResponse({ status: 200, description: 'List of supported adapter types' })
  getSupportedTypes() {
    return {
      types: this.adapterConfigService.getSupportedAdapterTypes(),
    };
  }

  @Get('types/:type')
  @ApiOperation({ summary: 'Get adapter type information' })
  @ApiParam({ name: 'type', enum: ['github', 'gitlab', 'jira', 'confluence', 'azure_devops'] })
  @ApiResponse({ status: 200, description: 'Adapter type information' })
  getTypeInfo(@Param('type') type: AdapterType) {
    return this.adapterConfigService.getAdapterTypeInfo(type);
  }

  // ==================== ADAPTER CONFIGURATIONS ====================

  @Get('configs')
  @ApiOperation({ summary: 'List all adapter configurations' })
  @ApiQuery({ name: 'tenantId', required: true })
  @ApiQuery({
    name: 'type',
    required: false,
    enum: ['github', 'gitlab', 'jira', 'confluence', 'azure_devops'],
  })
  @ApiQuery({ name: 'enabled', required: false, type: Boolean })
  @ApiResponse({ status: 200, description: 'List of adapter configurations' })
  async listConfigs(
    @Query('tenantId') tenantId: string,
    @Query('type') type?: AdapterType,
    @Query('enabled') enabled?: boolean,
  ) {
    let configs = await this.adapterConfigService.getAdapterConfigs(tenantId);

    if (type) {
      configs = configs.filter((c) => c.type === type);
    }

    if (enabled !== undefined) {
      configs = configs.filter((c) => c.enabled === enabled);
    }

    // Redact sensitive fields
    return {
      configs: configs.map((c) => this.redactSensitiveFields(c)),
    };
  }

  @Get('configs/:adapterId')
  @ApiOperation({ summary: 'Get adapter configuration by ID' })
  @ApiParam({ name: 'adapterId' })
  @ApiQuery({ name: 'tenantId', required: true })
  @ApiResponse({ status: 200, description: 'Adapter configuration' })
  @ApiResponse({ status: 404, description: 'Adapter not found' })
  async getConfig(@Param('adapterId') adapterId: string, @Query('tenantId') tenantId: string) {
    const config = await this.adapterConfigService.getAdapterConfig(tenantId, adapterId);
    if (!config) {
      throw new NotFoundException(`Adapter ${adapterId} not found`);
    }
    return this.redactSensitiveFields(config);
  }

  @Post('configs')
  @ApiOperation({ summary: 'Create a new adapter configuration' })
  @ApiQuery({ name: 'tenantId', required: true })
  @ApiResponse({ status: 201, description: 'Adapter configuration created' })
  @ApiResponse({ status: 400, description: 'Invalid configuration' })
  async createConfig(@Query('tenantId') tenantId: string, @Body() dto: CreateAdapterConfigDto) {
    // Validate configuration
    const validation = this.adapterConfigService.validateConfig(dto.type, dto.config);
    if (!validation.valid) {
      throw new BadRequestException(validation.errors.join(', '));
    }

    const config = await this.adapterConfigService.upsertAdapterConfig(tenantId, dto);
    return this.redactSensitiveFields(config);
  }

  @Put('configs/:adapterId')
  @ApiOperation({ summary: 'Update an adapter configuration' })
  @ApiParam({ name: 'adapterId' })
  @ApiQuery({ name: 'tenantId', required: true })
  @ApiResponse({ status: 200, description: 'Adapter configuration updated' })
  @ApiResponse({ status: 404, description: 'Adapter not found' })
  async updateConfig(
    @Param('adapterId') adapterId: string,
    @Query('tenantId') tenantId: string,
    @Body() dto: UpdateAdapterConfigDto,
  ) {
    const existing = await this.adapterConfigService.getAdapterConfig(tenantId, adapterId);
    if (!existing) {
      throw new NotFoundException(`Adapter ${adapterId} not found`);
    }

    if (dto.config) {
      const validation = this.adapterConfigService.validateConfig(existing.type, {
        ...existing.config,
        ...dto.config,
      });
      if (!validation.valid) {
        throw new BadRequestException(validation.errors.join(', '));
      }
    }

    const config = await this.adapterConfigService.upsertAdapterConfig(tenantId, {
      ...existing,
      ...dto,
      id: adapterId,
      config: dto.config ? { ...existing.config, ...dto.config } : existing.config,
    });

    return this.redactSensitiveFields(config);
  }

  @Delete('configs/:adapterId')
  @HttpCode(HttpStatus.NO_CONTENT)
  @ApiOperation({ summary: 'Delete an adapter configuration' })
  @ApiParam({ name: 'adapterId' })
  @ApiQuery({ name: 'tenantId', required: true })
  @ApiResponse({ status: 204, description: 'Adapter configuration deleted' })
  async deleteConfig(@Param('adapterId') adapterId: string, @Query('tenantId') tenantId: string) {
    await this.adapterConfigService.deleteAdapterConfig(tenantId, adapterId);
  }

  // ==================== CONNECTION TESTING ====================

  @Post('test-connection')
  @ApiOperation({ summary: 'Test adapter connection' })
  @ApiResponse({ status: 200, description: 'Connection test result' })
  async testConnection(@Body() dto: TestAdapterConnectionDto) {
    try {
      switch (dto.type) {
        case 'github': {
          const config = dto.config as unknown as GitHubAdapterConfig;
          // Try to fetch a single PR to test connection
          await this.githubAdapter.fetchPullRequests(
            { token: config.token, owner: config.owner, repo: config.repo },
            { perPage: 1 },
          );
          return { success: true, message: 'GitHub connection successful' };
        }

        case 'gitlab': {
          const config = dto.config as unknown as GitLabAdapterConfig;
          await this.gitlabAdapter.fetchPipelines(
            { token: config.token, projectId: config.projectId, apiUrl: config.apiUrl },
            { perPage: 1 },
          );
          return { success: true, message: 'GitLab connection successful' };
        }

        case 'jira': {
          const config = dto.config as unknown as JiraAdapterConfig;
          await this.jiraConfluenceAdapter.fetchProject(
            { domain: config.domain, email: config.email, apiToken: config.apiToken },
            config.projectKey,
          );
          return { success: true, message: 'Jira connection successful' };
        }

        case 'confluence': {
          const config = dto.config as unknown as ConfluenceAdapterConfig;
          await this.jiraConfluenceAdapter.searchPages(
            {
              domain: config.domain,
              email: config.email,
              apiToken: config.apiToken,
              spaceKey: config.spaceKey,
            },
            { limit: 1 },
          );
          return { success: true, message: 'Confluence connection successful' };
        }

        default:
          throw new BadRequestException(`Unsupported adapter type: ${dto.type}`);
      }
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : 'Unknown error';
      return {
        success: false,
        message: `Connection failed: ${errorMessage}`,
        error: errorMessage,
      };
    }
  }

  // ==================== SYNC OPERATIONS ====================

  @Post('configs/:adapterId/sync')
  @ApiOperation({ summary: 'Trigger evidence sync for an adapter' })
  @ApiParam({ name: 'adapterId' })
  @ApiQuery({ name: 'tenantId', required: true })
  @ApiResponse({ status: 200, description: 'Sync results' })
  async syncAdapter(
    @Param('adapterId') adapterId: string,
    @Query('tenantId') tenantId: string,
    @Body() dto: SyncAdapterDto,
  ) {
    const config = await this.adapterConfigService.getAdapterConfig(tenantId, adapterId);
    if (!config) {
      throw new NotFoundException(`Adapter ${adapterId} not found`);
    }

    if (!config.enabled) {
      throw new BadRequestException('Adapter is disabled');
    }

    // Update sync status
    await this.adapterConfigService.updateSyncStatus(tenantId, adapterId, 'syncing');

    try {
      let result: { ingested: number; errors: string[]; results: Record<string, number> };

      switch (config.type) {
        case 'github': {
          const githubConfig = config.config as unknown as GitHubAdapterConfig;
          result = await this.githubAdapter.ingestAllEvidence(
            {
              token: githubConfig.token,
              owner: githubConfig.owner,
              repo: githubConfig.repo,
              apiUrl: githubConfig.apiUrl,
            },
            dto.sessionId,
          );
          break;
        }

        case 'gitlab': {
          const gitlabConfig = config.config as unknown as GitLabAdapterConfig;
          result = await this.gitlabAdapter.ingestAllEvidence(
            {
              token: gitlabConfig.token,
              projectId: gitlabConfig.projectId,
              apiUrl: gitlabConfig.apiUrl,
            },
            dto.sessionId,
          );
          break;
        }

        case 'jira':
        case 'confluence': {
          const atlassianConfig = config.config as unknown as JiraAdapterConfig & {
            spaceKey?: string;
          };
          const confluenceConfig =
            config.type === 'confluence' || atlassianConfig.spaceKey
              ? {
                  domain: atlassianConfig.domain,
                  email: atlassianConfig.email,
                  apiToken: atlassianConfig.apiToken,
                  spaceKey: atlassianConfig.spaceKey ?? '',
                }
              : null;

          result = await this.jiraConfluenceAdapter.ingestAllEvidence(
            {
              domain: atlassianConfig.domain,
              email: atlassianConfig.email,
              apiToken: atlassianConfig.apiToken,
            },
            confluenceConfig,
            dto.sessionId,
            atlassianConfig.projectKey,
          );
          break;
        }

        default:
          throw new BadRequestException(`Sync not implemented for ${config.type}`);
      }

      // Update sync status to success
      await this.adapterConfigService.updateSyncStatus(tenantId, adapterId, 'success');

      return {
        adapterId,
        adapterType: config.type,
        sessionId: dto.sessionId,
        ...result,
      };
    } catch (error) {
      // Update sync status to error
      const errorMessage = error instanceof Error ? error.message : 'Unknown error';
      await this.adapterConfigService.updateSyncStatus(tenantId, adapterId, 'error', errorMessage);
      throw error;
    }
  }

  @Post('sync-all')
  @ApiOperation({ summary: 'Sync all enabled adapters' })
  @ApiQuery({ name: 'tenantId', required: true })
  @ApiResponse({ status: 200, description: 'Sync results for all adapters' })
  async syncAllAdapters(@Query('tenantId') tenantId: string, @Body() dto: SyncAdapterDto) {
    const enabledAdapters = await this.adapterConfigService.getEnabledAdapters(tenantId);
    const results: Array<{
      adapterId: string;
      adapterType: AdapterType;
      success: boolean;
      ingested?: number;
      error?: string;
    }> = [];

    for (const adapter of enabledAdapters) {
      try {
        const result = await this.syncAdapter(adapter.id, tenantId, dto);
        results.push({
          adapterId: adapter.id,
          adapterType: adapter.type,
          success: true,
          ingested: result.ingested,
        });
      } catch (error) {
        results.push({
          adapterId: adapter.id,
          adapterType: adapter.type,
          success: false,
          error: error instanceof Error ? error.message : 'Unknown error',
        });
      }
    }

    const totalIngested = results.reduce((sum, r) => sum + (r.ingested || 0), 0);
    const successCount = results.filter((r) => r.success).length;

    return {
      sessionId: dto.sessionId,
      totalAdapters: enabledAdapters.length,
      successfulSyncs: successCount,
      failedSyncs: enabledAdapters.length - successCount,
      totalIngested,
      results,
    };
  }

  // ==================== WEBHOOKS ====================

  private readonly webhookLogger = new Logger('AdapterWebhook');

  /**
   * Verify GitHub webhook signature using HMAC-SHA256
   * @see https://docs.github.com/en/webhooks/using-webhooks/validating-webhook-deliveries
   */
  private verifyGitHubSignature(payload: string, signature: string, secret: string): boolean {
    const expected = 'sha256=' + crypto.createHmac('sha256', secret).update(payload).digest('hex');
    return (
      signature.length === expected.length &&
      crypto.timingSafeEqual(Buffer.from(signature), Buffer.from(expected))
    );
  }

  @Public()
  @Post('webhooks/github')
  @HttpCode(HttpStatus.OK)
  @ApiOperation({ summary: 'GitHub webhook endpoint — authenticated via HMAC signature, not JWT' })
  async handleGitHubWebhook(
    @Body() payload: Record<string, unknown>,
    @Headers('x-hub-signature-256') signature: string,
    @Query('adapterId') adapterId: string,
    @Query('tenantId') tenantId: string,
  ) {
    const config = await this.adapterConfigService.getAdapterConfig(tenantId, adapterId);
    if (!config || !config.enabled) {
      return { status: 'ignored', reason: 'Adapter not found or disabled' };
    }

    // Verify webhook signature
    const webhookSecret = (config as AdapterConfig & { webhookSecret?: string }).webhookSecret;
    if (webhookSecret && signature) {
      const isValid = this.verifyGitHubSignature(JSON.stringify(payload), signature, webhookSecret);
      if (!isValid) {
        this.webhookLogger.warn(`GitHub webhook signature mismatch for adapter ${adapterId}`);
        throw new BadRequestException('Invalid webhook signature');
      }
    } else {
      this.webhookLogger.warn(`GitHub webhook received without signature for adapter ${adapterId}`);
    }

    return {
      status: 'received',
      adapterId,
      event: payload.action || 'unknown',
    };
  }

  @Public()
  @Post('webhooks/gitlab')
  @HttpCode(HttpStatus.OK)
  @ApiOperation({ summary: 'GitLab webhook endpoint — authenticated via secret token, not JWT' })
  async handleGitLabWebhook(
    @Body() payload: Record<string, unknown>,
    @Headers('x-gitlab-token') gitlabToken: string,
    @Query('adapterId') adapterId: string,
    @Query('tenantId') tenantId: string,
  ) {
    const config = await this.adapterConfigService.getAdapterConfig(tenantId, adapterId);
    if (!config || !config.enabled) {
      return { status: 'ignored', reason: 'Adapter not found or disabled' };
    }

    // Verify GitLab secret token
    const webhookSecret = (config as AdapterConfig & { webhookSecret?: string }).webhookSecret;
    if (webhookSecret) {
      // Use constant-time comparison to avoid timing side-channels on webhook secrets
      if (!gitlabToken) {
        this.webhookLogger.warn(`GitLab webhook token mismatch for adapter ${adapterId}`);
        throw new BadRequestException('Invalid webhook token');
      }

      const webhookSecretBuffer = Buffer.from(webhookSecret, 'utf8');
      const gitlabTokenBuffer = Buffer.from(gitlabToken, 'utf8');

      if (
        gitlabTokenBuffer.length !== webhookSecretBuffer.length ||
        !crypto.timingSafeEqual(gitlabTokenBuffer, webhookSecretBuffer)
      ) {
        this.webhookLogger.warn(`GitLab webhook token mismatch for adapter ${adapterId}`);
        throw new BadRequestException('Invalid webhook token');
      }
    } else {
      this.webhookLogger.warn(`GitLab webhook received without token for adapter ${adapterId}`);
    }

    return {
      status: 'received',
      adapterId,
      event: payload.object_kind || 'unknown',
    };
  }

  // ==================== HELPERS ====================

  private redactSensitiveFields(config: AdapterConfig): AdapterConfig {
    const redacted = { ...config, config: { ...config.config } };
    const sensitiveFields = [
      'token',
      'apiToken',
      'personalAccessToken',
      'webhookSecret',
      'webhookToken',
    ];

    for (const field of sensitiveFields) {
      if (redacted.config[field]) {
        redacted.config[field] = '***REDACTED***';
      }
    }

    return redacted;
  }
}

import { Injectable, Logger, HttpException, HttpStatus } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { PrismaService } from '@libs/database';
import { createHash } from 'crypto';

// Helper to extract error message from unknown error type
function getErrorMessage(error: unknown): string {
  if (error instanceof Error) {
    return error.message;
  }
  if (typeof error === 'string') {
    return error;
  }
  return 'Unknown error';
}

interface GitHubConfig {
  token: string;
  owner: string;
  repo: string;
  apiUrl?: string;
}

interface GitHubPullRequest {
  id: number;
  number: number;
  title: string;
  state: string;
  merged: boolean;
  merged_at: string | null;
  user: { login: string };
  base: { ref: string };
  head: { ref: string; sha: string };
  created_at: string;
  updated_at: string;
  html_url: string;
  additions: number;
  deletions: number;
  changed_files: number;
  mergeable: boolean | null;
  review_comments: number;
  commits: number;
}

interface GitHubCheckRun {
  id: number;
  name: string;
  status: string;
  conclusion: string | null;
  started_at: string;
  completed_at: string | null;
  html_url: string;
  output: {
    title: string | null;
    summary: string | null;
    annotations_count: number;
  };
}

interface GitHubRelease {
  id: number;
  tag_name: string;
  name: string;
  body: string;
  draft: boolean;
  prerelease: boolean;
  created_at: string;
  published_at: string;
  html_url: string;
  assets: GitHubReleaseAsset[];
}

interface GitHubReleaseAsset {
  id: number;
  name: string;
  content_type: string;
  size: number;
  download_count: number;
  browser_download_url: string;
}

interface GitHubWorkflowRun {
  id: number;
  name: string;
  status: string;
  conclusion: string | null;
  workflow_id: number;
  run_number: number;
  event: string;
  created_at: string;
  updated_at: string;
  html_url: string;
  head_sha: string;
  head_branch: string;
}

interface GitHubArtifact {
  id: number;
  name: string;
  size_in_bytes: number;
  archive_download_url: string;
  expired: boolean;
  created_at: string;
  expires_at: string;
}

export interface GitHubEvidenceResult {
  type: 'pull_request' | 'check_run' | 'release' | 'workflow_run' | 'sbom' | 'security_advisory';
  sourceId: string;
  sourceUrl: string;
  data: Record<string, unknown>;
  hash: string;
  timestamp: Date;
  metadata: Record<string, unknown>;
}

@Injectable()
export class GitHubAdapter {
  private readonly logger = new Logger(GitHubAdapter.name);
  private readonly defaultApiUrl = 'https://api.github.com';

  constructor(_configService: ConfigService, _prisma: PrismaService) {}

  private getHeaders(token: string): Record<string, string> {
    return {
      Authorization: `Bearer ${token}`,
      Accept: 'application/vnd.github+json',
      'X-GitHub-Api-Version': '2022-11-28',
    };
  }

  private async makeRequest<T>(
    config: GitHubConfig,
    endpoint: string,
    method: string = 'GET',
    body?: unknown,
  ): Promise<T> {
    const baseUrl = config.apiUrl || this.defaultApiUrl;
    const url = `${baseUrl}${endpoint}`;

    try {
      const response = await fetch(url, {
        method,
        headers: this.getHeaders(config.token),
        body: body ? JSON.stringify(body) : undefined,
      });

      if (!response.ok) {
        const errorBody = await response.text();
        throw new HttpException(
          `GitHub API error: ${response.status} - ${errorBody}`,
          response.status,
        );
      }

      return (await response.json()) as T;
    } catch (error) {
      if (error instanceof HttpException) {
        throw error;
      }
      this.logger.error(`GitHub API request failed: ${getErrorMessage(error)}`);
      throw new HttpException('Failed to connect to GitHub API', HttpStatus.SERVICE_UNAVAILABLE);
    }
  }

  private calculateHash(data: unknown): string {
    return createHash('sha256').update(JSON.stringify(data)).digest('hex');
  }

  /**
   * Fetch pull requests and convert to evidence
   */
  async fetchPullRequests(
    config: GitHubConfig,
    options: { state?: 'open' | 'closed' | 'all'; perPage?: number; page?: number } = {},
  ): Promise<GitHubEvidenceResult[]> {
    const { state = 'all', perPage = 30, page = 1 } = options;
    const endpoint = `/repos/${config.owner}/${config.repo}/pulls?state=${state}&per_page=${perPage}&page=${page}`;

    const pullRequests = await this.makeRequest<GitHubPullRequest[]>(config, endpoint);

    return pullRequests.map((pr) => ({
      type: 'pull_request' as const,
      sourceId: `github-pr-${pr.number}`,
      sourceUrl: pr.html_url,
      data: {
        number: pr.number,
        title: pr.title,
        state: pr.state,
        merged: pr.merged,
        mergedAt: pr.merged_at,
        author: pr.user.login,
        baseBranch: pr.base.ref,
        headBranch: pr.head.ref,
        headSha: pr.head.sha,
        additions: pr.additions,
        deletions: pr.deletions,
        changedFiles: pr.changed_files,
        reviewComments: pr.review_comments,
        commits: pr.commits,
      },
      hash: this.calculateHash(pr),
      timestamp: new Date(pr.updated_at),
      metadata: {
        provider: 'github',
        owner: config.owner,
        repo: config.repo,
        resourceType: 'pull_request',
      },
    }));
  }

  /**
   * Fetch check runs for a specific commit SHA
   */
  async fetchCheckRuns(config: GitHubConfig, commitSha: string): Promise<GitHubEvidenceResult[]> {
    const endpoint = `/repos/${config.owner}/${config.repo}/commits/${commitSha}/check-runs`;

    const response = await this.makeRequest<{ check_runs: GitHubCheckRun[] }>(config, endpoint);

    return response.check_runs.map((check) => ({
      type: 'check_run' as const,
      sourceId: `github-check-${check.id}`,
      sourceUrl: check.html_url,
      data: {
        name: check.name,
        status: check.status,
        conclusion: check.conclusion,
        startedAt: check.started_at,
        completedAt: check.completed_at,
        annotationsCount: check.output.annotations_count,
        outputTitle: check.output.title,
        outputSummary: check.output.summary,
      },
      hash: this.calculateHash(check),
      timestamp: new Date(check.completed_at || check.started_at),
      metadata: {
        provider: 'github',
        owner: config.owner,
        repo: config.repo,
        commitSha,
        resourceType: 'check_run',
      },
    }));
  }

  /**
   * Fetch workflow runs
   */
  async fetchWorkflowRuns(
    config: GitHubConfig,
    options: { perPage?: number; page?: number; status?: string } = {},
  ): Promise<GitHubEvidenceResult[]> {
    const { perPage = 30, page = 1, status } = options;
    let endpoint = `/repos/${config.owner}/${config.repo}/actions/runs?per_page=${perPage}&page=${page}`;
    if (status) {
      endpoint += `&status=${status}`;
    }

    const response = await this.makeRequest<{ workflow_runs: GitHubWorkflowRun[] }>(
      config,
      endpoint,
    );

    return response.workflow_runs.map((run) => ({
      type: 'workflow_run' as const,
      sourceId: `github-workflow-${run.id}`,
      sourceUrl: run.html_url,
      data: {
        name: run.name,
        status: run.status,
        conclusion: run.conclusion,
        workflowId: run.workflow_id,
        runNumber: run.run_number,
        event: run.event,
        headSha: run.head_sha,
        headBranch: run.head_branch,
        createdAt: run.created_at,
        updatedAt: run.updated_at,
      },
      hash: this.calculateHash(run),
      timestamp: new Date(run.updated_at),
      metadata: {
        provider: 'github',
        owner: config.owner,
        repo: config.repo,
        resourceType: 'workflow_run',
      },
    }));
  }

  /**
   * Fetch workflow artifacts (SBOM, test reports, etc.)
   */
  async fetchWorkflowArtifacts(
    config: GitHubConfig,
    runId: number,
  ): Promise<GitHubEvidenceResult[]> {
    const endpoint = `/repos/${config.owner}/${config.repo}/actions/runs/${runId}/artifacts`;

    const response = await this.makeRequest<{ artifacts: GitHubArtifact[] }>(config, endpoint);

    return response.artifacts
      .filter((artifact) => !artifact.expired)
      .map((artifact) => ({
        type: 'sbom' as const, // Classify artifacts that might be SBOMs
        sourceId: `github-artifact-${artifact.id}`,
        sourceUrl: artifact.archive_download_url,
        data: {
          name: artifact.name,
          sizeInBytes: artifact.size_in_bytes,
          createdAt: artifact.created_at,
          expiresAt: artifact.expires_at,
          downloadUrl: artifact.archive_download_url,
        },
        hash: this.calculateHash(artifact),
        timestamp: new Date(artifact.created_at),
        metadata: {
          provider: 'github',
          owner: config.owner,
          repo: config.repo,
          runId,
          resourceType: 'artifact',
          isSbom:
            artifact.name.toLowerCase().includes('sbom') ||
            artifact.name.toLowerCase().includes('cyclonedx') ||
            artifact.name.toLowerCase().includes('spdx'),
        },
      }));
  }

  /**
   * Fetch releases
   */
  async fetchReleases(
    config: GitHubConfig,
    options: { perPage?: number; page?: number } = {},
  ): Promise<GitHubEvidenceResult[]> {
    const { perPage = 30, page = 1 } = options;
    const endpoint = `/repos/${config.owner}/${config.repo}/releases?per_page=${perPage}&page=${page}`;

    const releases = await this.makeRequest<GitHubRelease[]>(config, endpoint);

    return releases.map((release) => ({
      type: 'release' as const,
      sourceId: `github-release-${release.id}`,
      sourceUrl: release.html_url,
      data: {
        tagName: release.tag_name,
        name: release.name,
        body: release.body,
        draft: release.draft,
        prerelease: release.prerelease,
        createdAt: release.created_at,
        publishedAt: release.published_at,
        assets: release.assets.map((a) => ({
          name: a.name,
          contentType: a.content_type,
          size: a.size,
          downloadCount: a.download_count,
          downloadUrl: a.browser_download_url,
        })),
      },
      hash: this.calculateHash(release),
      timestamp: new Date(release.published_at || release.created_at),
      metadata: {
        provider: 'github',
        owner: config.owner,
        repo: config.repo,
        resourceType: 'release',
      },
    }));
  }

  /**
   * Fetch Dependency Graph SBOM (GitHub native SBOM)
   */
  async fetchDependencyGraphSbom(config: GitHubConfig): Promise<GitHubEvidenceResult | null> {
    try {
      const endpoint = `/repos/${config.owner}/${config.repo}/dependency-graph/sbom`;
      const sbom = await this.makeRequest<{ sbom: Record<string, unknown> }>(config, endpoint);

      return {
        type: 'sbom' as const,
        sourceId: `github-sbom-${config.owner}-${config.repo}`,
        sourceUrl: `https://github.com/${config.owner}/${config.repo}/network/dependencies`,
        data: sbom.sbom,
        hash: this.calculateHash(sbom),
        timestamp: new Date(),
        metadata: {
          provider: 'github',
          owner: config.owner,
          repo: config.repo,
          resourceType: 'dependency_graph_sbom',
          format: 'spdx',
        },
      };
    } catch (error) {
      this.logger.warn(`Failed to fetch dependency graph SBOM: ${getErrorMessage(error)}`);
      return null;
    }
  }

  /**
   * Fetch security advisories (Dependabot alerts)
   */
  async fetchSecurityAdvisories(config: GitHubConfig): Promise<GitHubEvidenceResult[]> {
    try {
      const endpoint = `/repos/${config.owner}/${config.repo}/dependabot/alerts?state=open`;
      const alerts = await this.makeRequest<
        Array<{
          number: number;
          state: string;
          dependency: { package: { name: string; ecosystem: string }; manifest_path: string };
          security_advisory: {
            ghsa_id: string;
            cve_id: string | null;
            summary: string;
            severity: string;
          };
          security_vulnerability: { severity: string; vulnerable_version_range: string };
          created_at: string;
          html_url: string;
        }>
      >(config, endpoint);

      return alerts.map((alert) => ({
        type: 'security_advisory' as const,
        sourceId: `github-advisory-${alert.number}`,
        sourceUrl: alert.html_url,
        data: {
          alertNumber: alert.number,
          state: alert.state,
          package: alert.dependency.package.name,
          ecosystem: alert.dependency.package.ecosystem,
          manifestPath: alert.dependency.manifest_path,
          ghsaId: alert.security_advisory.ghsa_id,
          cveId: alert.security_advisory.cve_id,
          summary: alert.security_advisory.summary,
          severity: alert.security_advisory.severity,
          vulnerableVersionRange: alert.security_vulnerability.vulnerable_version_range,
        },
        hash: this.calculateHash(alert),
        timestamp: new Date(alert.created_at),
        metadata: {
          provider: 'github',
          owner: config.owner,
          repo: config.repo,
          resourceType: 'dependabot_alert',
        },
      }));
    } catch (error) {
      this.logger.warn(`Failed to fetch security advisories: ${getErrorMessage(error)}`);
      return [];
    }
  }

  /**
   * Ingest all evidence from a GitHub repository
   */
  async ingestAllEvidence(
    config: GitHubConfig,
    sessionId: string,
  ): Promise<{
    ingested: number;
    errors: string[];
    results: Record<string, number>;
  }> {
    const results: Record<string, number> = {
      pull_requests: 0,
      workflow_runs: 0,
      check_runs: 0,
      releases: 0,
      sbom: 0,
      security_advisories: 0,
    };
    const errors: string[] = [];
    let totalIngested = 0;

    // Fetch PRs
    try {
      const prs = await this.fetchPullRequests(config, { state: 'all', perPage: 50 });
      for (const pr of prs) {
        await this.saveEvidence(sessionId, pr);
        totalIngested++;
      }
      results.pull_requests = prs.length;
    } catch (error) {
      errors.push(`Pull requests: ${getErrorMessage(error)}`);
    }

    // Fetch workflow runs
    try {
      const runs = await this.fetchWorkflowRuns(config, { perPage: 20 });
      for (const run of runs) {
        await this.saveEvidence(sessionId, run);
        totalIngested++;
      }
      results.workflow_runs = runs.length;

      // Fetch check runs for recent commits
      const recentShas = [...new Set(runs.slice(0, 5).map((r) => r.data.headSha as string))];
      for (const sha of recentShas) {
        try {
          const checks = await this.fetchCheckRuns(config, sha);
          for (const check of checks) {
            await this.saveEvidence(sessionId, check);
            totalIngested++;
          }
          results.check_runs += checks.length;
        } catch (error) {
          errors.push(`Check runs for ${sha}: ${getErrorMessage(error)}`);
        }
      }
    } catch (error) {
      errors.push(`Workflow runs: ${getErrorMessage(error)}`);
    }

    // Fetch releases
    try {
      const releases = await this.fetchReleases(config, { perPage: 10 });
      for (const release of releases) {
        await this.saveEvidence(sessionId, release);
        totalIngested++;
      }
      results.releases = releases.length;
    } catch (error) {
      errors.push(`Releases: ${getErrorMessage(error)}`);
    }

    // Fetch SBOM
    try {
      const sbom = await this.fetchDependencyGraphSbom(config);
      if (sbom) {
        await this.saveEvidence(sessionId, sbom);
        totalIngested++;
        results.sbom = 1;
      }
    } catch (error) {
      errors.push(`SBOM: ${getErrorMessage(error)}`);
    }

    // Fetch security advisories
    try {
      const advisories = await this.fetchSecurityAdvisories(config);
      for (const advisory of advisories) {
        await this.saveEvidence(sessionId, advisory);
        totalIngested++;
      }
      results.security_advisories = advisories.length;
    } catch (error) {
      errors.push(`Security advisories: ${getErrorMessage(error)}`);
    }

    this.logger.log(
      `GitHub ingestion complete: ${totalIngested} items from ${config.owner}/${config.repo}`,
    );

    return {
      ingested: totalIngested,
      errors,
      results,
    };
  }

  /**
   * Save evidence - stores in memory/cache for later processing
   * Note: Actual persistence requires linking to EvidenceRegistry via questionId
   */
  private async saveEvidence(sessionId: string, evidence: GitHubEvidenceResult): Promise<void> {
    // Log evidence for audit trail
    this.logger.debug(
      `Ingested ${evidence.type} evidence: ${evidence.sourceId} for session ${sessionId}`,
    );
    // Evidence data is returned via ingestAllEvidence results
    // Actual database persistence should be handled by the calling service
    // after mapping to appropriate question/evidence relationships
  }

  /**
   * Verify GitHub webhook signature
   */
  verifyWebhookSignature(payload: string, signature: string, secret: string): boolean {
    const expectedSignature = `sha256=${createHash('sha256')
      .update(payload)
      .update(secret)
      .digest('hex')}`;

    return signature === expectedSignature;
  }
}

import { Injectable, Logger, HttpException, HttpStatus } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { PrismaService } from '@libs/database';
