import { EMAIL_TEMPLATES, EmailTemplateData } from './dto/email-template.dto';

/**
 * Email Provider Interface for swappable email backends
 */
interface EmailProvider {
  send(
    to: string,
    subject: string,
    html: string,
    text?: string,
  ): Promise<{ messageId?: string; success: boolean; error?: string }>;
}

/**
 * Brevo (formerly Sendinblue) Email Provider Implementation
 */
class BrevoProvider implements EmailProvider {
  private readonly apiKey: string;
  private readonly fromEmail: string;
  private readonly fromName: string;
  private readonly logger = new Logger('BrevoProvider');

  constructor(apiKey: string, fromEmail: string, fromName: string) {
    this.apiKey = apiKey;
    this.fromEmail = fromEmail;
    this.fromName = fromName;
  }

  async send(
    to: string,
    subject: string,
    html: string,
    text?: string,
  ): Promise<{ messageId?: string; success: boolean; error?: string }> {
    try {
      const response = await fetch('https://api.brevo.com/v3/smtp/email', {
        method: 'POST',
        headers: {
          'api-key': this.apiKey,
          'Content-Type': 'application/json',
          Accept: 'application/json',
        },
        body: JSON.stringify({
          sender: { email: this.fromEmail, name: this.fromName },
          to: [{ email: to }],
          subject,
          htmlContent: html,
          ...(text && { textContent: text }),
        }),
      });

      if (response.ok) {
        const data = (await response.json()) as { messageId?: string };
        return { success: true, messageId: data.messageId };
      }

      const errorBody = await response.text();
      this.logger.error(`Brevo error: ${response.status} - ${errorBody}`);
      return { success: false, error: `Brevo error: ${response.status}` };
    } catch (error) {
      this.logger.error('Brevo request failed', error);
      return { success: false, error: error instanceof Error ? error.message : 'Unknown error' };
    }
  }
}

/**
 * SendGrid Email Provider Implementation (legacy fallback)
 */
class SendGridProvider implements EmailProvider {
  private readonly apiKey: string;
  private readonly fromEmail: string;
  private readonly fromName: string;
  private readonly logger = new Logger('SendGridProvider');

  constructor(apiKey: string, fromEmail: string, fromName: string) {
    this.apiKey = apiKey;
    this.fromEmail = fromEmail;
    this.fromName = fromName;
  }

  async send(
    to: string,
    subject: string,
    html: string,
    text?: string,
  ): Promise<{ messageId?: string; success: boolean; error?: string }> {
    try {
      // Using fetch for SendGrid v3 API
      const response = await fetch('https://api.sendgrid.com/v3/mail/send', {
        method: 'POST',
        headers: {
          Authorization: `Bearer ${this.apiKey}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          personalizations: [{ to: [{ email: to }] }],
          from: { email: this.fromEmail, name: this.fromName },
          subject,
          content: [
            ...(text ? [{ type: 'text/plain', value: text }] : []),
            { type: 'text/html', value: html },
          ],
        }),
      });

      if (response.ok || response.status === 202) {
        const messageId = response.headers.get('x-message-id') || undefined;
        return { success: true, messageId };
      }

      const errorBody = await response.text();
      this.logger.error(`SendGrid error: ${response.status} - ${errorBody}`);
      return { success: false, error: `SendGrid error: ${response.status}` };
    } catch (error) {
      this.logger.error('SendGrid request failed', error);
      return { success: false, error: error instanceof Error ? error.message : 'Unknown error' };
    }
  }
}

